// Route GitLab webhook events to Plane API calls
const body = $input.item.json.body || $input.item.json;
const headers = $input.item.json.headers || {};

// Verify webhook token
const expectedToken = 'gitlab-plane-webhook-secret';
const receivedToken = headers['x-gitlab-token'] || '';
if (receivedToken !== expectedToken) {
  return { json: { error: 'Invalid webhook token', _status: 401 } };
}

const eventType = headers['x-gitlab-event'] || '';
const PLANE_API = 'http://genai-plane-api.genai.svc.cluster.local:8000';
const WORKSPACE = 'r-aas';
// Platform Monorepo project ID in Plane
const PLANE_PROJECT = '1b0b93eb-5915-4338-bd16-16a04acdb429';
const PLANE_TOKEN = $env.PLANE_API_TOKEN || '';

// State IDs from Plane
const STATES = {
  backlog: 'cfc8f7cd-daaf-4d5a-819e-f59b5d3b36c9',
  todo: '3eaae951-b70c-4b09-8a46-d7094e10ae97',
  in_progress: '44c20543-a3f6-4769-90fe-56f93342a71a',
  done: 'cb7fc63e-8e56-4962-90c9-de3054067c4f',
  cancelled: '0eee9bc5-5cd9-4887-96ff-a77d1e9227ec'
};

let action = 'skip';
let call_url = '';
let call_method = 'POST';
let call_body = {};
let summary = '';

if (eventType === 'Push Hook') {
  // Push events — create a comment on the latest relevant issue or skip
  const ref = body.ref || '';
  const branch = ref.replace('refs/heads/', '');
  const commits = body.commits || [];
  const totalCommits = body.total_commits_count || commits.length;
  const repoName = (body.project || {}).name || 'unknown';
  const commitMessages = commits.slice(0, 5).map(c => `- \`${c.id.substring(0,8)}\` ${c.message.split('\n')[0]}`).join('\n');

  summary = `Push to ${repoName}/${branch}: ${totalCommits} commit(s)\n${commitMessages}`;

  // Create as a backlog issue tracking the push
  action = 'create_issue';
  call_url = `${PLANE_API}/api/v1/workspaces/${WORKSPACE}/projects/${PLANE_PROJECT}/issues/`;
  call_body = {
    name: `[Push] ${branch}: ${totalCommits} commit(s) — ${repoName}`,
    description_html: `<p><strong>Branch:</strong> ${branch}</p><p><strong>Commits:</strong></p><pre>${commitMessages}</pre>`,
    state_id: STATES.done,
    priority: 'none'
  };

} else if (eventType === 'Issue Hook') {
  const issue = body.object_attributes || {};
  const issueAction = issue.action || '';
  const title = issue.title || 'Untitled';
  const description = issue.description || '';
  const url = issue.url || '';
  const author = (body.user || {}).name || 'unknown';
  const labels = (body.labels || []).map(l => l.title).join(', ');

  if (issueAction === 'open') {
    action = 'create_issue';
    call_url = `${PLANE_API}/api/v1/workspaces/${WORKSPACE}/projects/${PLANE_PROJECT}/issues/`;
    call_body = {
      name: `[GitLab] ${title}`,
      description_html: `<p><strong>From GitLab:</strong> <a href="${url}">${url}</a></p><p><strong>Author:</strong> ${author}</p>${labels ? `<p><strong>Labels:</strong> ${labels}</p>` : ''}<hr/><p>${description}</p>`,
      state_id: STATES.todo,
      priority: 'medium'
    };
    summary = `GitLab issue opened: ${title} by ${author}`;
  } else if (issueAction === 'close') {
    // Can't easily find the Plane issue — log it
    action = 'create_issue';
    call_url = `${PLANE_API}/api/v1/workspaces/${WORKSPACE}/projects/${PLANE_PROJECT}/issues/`;
    call_body = {
      name: `[GitLab Closed] ${title}`,
      description_html: `<p>GitLab issue closed: <a href="${url}">${url}</a></p>`,
      state_id: STATES.done,
      priority: 'none'
    };
    summary = `GitLab issue closed: ${title}`;
  } else {
    action = 'skip';
    summary = `GitLab issue action '${issueAction}' — skipped`;
  }

} else if (eventType === 'Merge Request Hook') {
  const mr = body.object_attributes || {};
  const mrAction = mr.action || '';
  const title = mr.title || 'Untitled MR';
  const url = mr.url || '';
  const author = (body.user || {}).name || 'unknown';
  const sourceBranch = mr.source_branch || '';
  const targetBranch = mr.target_branch || '';
  const state = mr.state || '';

  let planeState = STATES.todo;
  let priority = 'medium';
  if (mrAction === 'merge' || state === 'merged') {
    planeState = STATES.done;
    priority = 'none';
  } else if (mrAction === 'open' || mrAction === 'reopen') {
    planeState = STATES.in_progress;
    priority = 'high';
  } else if (mrAction === 'close') {
    planeState = STATES.cancelled;
    priority = 'none';
  }

  action = 'create_issue';
  call_url = `${PLANE_API}/api/v1/workspaces/${WORKSPACE}/projects/${PLANE_PROJECT}/issues/`;
  call_body = {
    name: `[MR ${mrAction}] ${title}`,
    description_html: `<p><strong>MR:</strong> <a href="${url}">${url}</a></p><p><strong>Author:</strong> ${author}</p><p><strong>Branch:</strong> ${sourceBranch} → ${targetBranch}</p>`,
    state_id: planeState,
    priority: priority
  };
  summary = `MR ${mrAction}: ${title} (${sourceBranch} → ${targetBranch})`;

} else if (eventType === 'Note Hook') {
  const note = body.object_attributes || {};
  const noteableType = note.noteable_type || '';
  const noteBody = note.note || '';
  const url = note.url || '';
  const author = (body.user || {}).name || 'unknown';

  // Only track MR and issue comments
  if (noteableType === 'MergeRequest' || noteableType === 'Issue') {
    action = 'create_issue';
    call_url = `${PLANE_API}/api/v1/workspaces/${WORKSPACE}/projects/${PLANE_PROJECT}/issues/`;
    call_body = {
      name: `[Comment] ${noteableType} comment by ${author}`,
      description_html: `<p><strong>${noteableType} comment by ${author}:</strong></p><p><a href="${url}">${url}</a></p><blockquote>${noteBody.substring(0, 500)}</blockquote>`,
      state_id: STATES.done,
      priority: 'none'
    };
    summary = `Comment on ${noteableType} by ${author}`;
  } else {
    action = 'skip';
    summary = `Note on ${noteableType} — skipped`;
  }

} else {
  action = 'skip';
  summary = `Unknown event type: ${eventType}`;
}

return {
  json: {
    action,
    call_url,
    call_method,
    call_body: JSON.stringify(call_body),
    summary,
    event_type: eventType,
    plane_token: PLANE_TOKEN
  }
};

const planeResponse = $input.item.json;
const routeData = $('Route Event').item.json;

return {
  json: {
    ok: true,
    event_type: routeData.event_type,
    action: routeData.action,
    summary: routeData.summary,
    plane_issue_id: planeResponse.id || null,
    plane_issue_identifier: planeResponse.project_detail ? `${planeResponse.project_detail.identifier}-${planeResponse.sequence_id}` : null
  }
};

const routeData = $('Route Event').item.json;

return {
  json: {
    ok: true,
    event_type: routeData.event_type,
    action: 'skipped',
    summary: routeData.summary
  }
};
